proof fn phi_2_rids_match_all_none_empty_rids(bools: Seq<Option<ReqId>>, rids: Seq<ReqId>, bools_start: nat, bools_end: nat, rids_pos: nat)
    requires
        0 <= bools_start <= bools_end <= bools.len(),
        rids_pos <= rids.len(),
        forall |i: nat| bools_start <= i < bools_end ==> bools[i as int].is_None(),
    ensures
        rids_match(bools, rids, bools_start, bools_end, rids_pos, rids_pos),
    decreases bools_end - bools_start,
{
    if bools_end > bools_start {
        phi_2_rids_match_all_none_empty_rids(bools, rids, bools_start, (bools_end - 1) as nat, rids_pos);
    }
}

proof fn phi_4_rids_match_add_none_extends(bools: Seq<Option<ReqId>>, rids: Seq<ReqId>, bools_start: nat, bools_end: nat, rids_start: nat, rids_end: nat)
    requires
        0 <= bools_start <= bools_end <= bools.len(),
        0 <= rids_start <= rids_end <= rids.len(),
        rids_match(bools, rids, bools_start, bools_end, rids_start, rids_end),
    ensures
        rids_match(bools.push(Option::None), rids, bools_start, (bools_end + 1) as nat, rids_start, rids_end),
{
    rids_match_add_none(bools, rids, bools_start, bools_end, rids_start, rids_end);
    // After push, bools_new[bools_end] == None, so extending bools_end by 1 skips it
}

